; ---------------------------------------------------------------------------
; Range clamp functions
;
; Limits table format (pointed to by Y on entry):
;   Y[0]: min value (1 byte)
;   Y[1]: max value (1 byte)
;
; Called via indexed JSR: jsr y + (clamp_rB - limits_table)
; This allows a limits table in RAM/ROM to select which clamp to use
; by offsetting into the table to the appropriate function entry point.
;
; Returns: D = clamped value
;          C set if value was clamped, clear if within range
; ---------------------------------------------------------------------------

clamp_rB:							; CODE XREF: divide_d_by_x+AD3p
								; divide_d_by_x+B87p ...
; Clamp B against limits at Y[0..1]. Entry point assumes Y points one byte
; past the min value (i.e. Y-1 = min, Y = max). Adjusts Y back before check.
				dec	y			; Y-- : Y now points to min value
				cmp	b, y + 01h		; Compare B against max (Y[1])
				bgt	loc_C3EA		; If B > max, clamp to max

				ld	a, y + 01h		; A = max (used as upper limit for clamp_rD path)
				bra	loc_C3E5		; Jump into clamp_rD to check lower bound

; End of function clamp_rB


; ��������������� S U B	R O U T	I N E ���������������������������������������


clamp_rD:							; CODE XREF: sub_E865+42p
								; sub_E865+88p
								; DATA XREF: ...
; Clamp D (16-bit) against limits at Y[0..1] (min, max).
; On entry: Y = pointer to [min (1 byte), max (1 byte)]
				cmp	d, y + 00h		; Compare D against min
				bgt	loc_C3EA		; If D > min (i.e. D >= min), check upper bound

				inc	y			; D <= min: Y++ to point at max byte

loc_C3E5:							; CODE XREF: clamp_rB+7j
; Check upper bound
				inc	y			; Y++ : Y now points to max value
				cmp	d, y + 00h		; Compare D against max
				bcc	locret_C3ED		; If D < max, value is within range - return C clear


loc_C3EA:							; CODE XREF: clamp_rB+3j
								; clamp_rD+2j
; Value is out of range: load boundary value and set C to signal clamping
				ld	d, y + 00h		; D = boundary value (min or max)
				setc				; C = 1: value was clamped

locret_C3ED:							; CODE XREF: clamp_rD+8j
				ret

; End of function clamp_rD


