; ---------------------------------------------------------------------------
; 1D Lookup Table Interpolation - Wrapper Functions
;
; Table format in ROM:
;   Byte 0:        N = number of data bytes (= number of pairs * 2)
;   Bytes 1..N:    Pairs of [x, y] values, each 1 byte, in ascending x order
;
; Calling convention for table_pair_interpolate:
;   Y  = pointer to table (byte 0 = count)
;   D (A:B) = input value (A = x input to look up, B = 0)
;
; Returns:
;   A  = interpolated y value (integer part)
;   B  = fractional part (0..255, where 255 = just under 1 step)
;
; Result formula (when input falls between two table entries):
;   frac = (A_in - x0) * 256 / (x1 - x0)          [0..255]
;   A_out = y0 + (y1 - y0) * frac / 256
;   B_out = fractional remainder of the above multiply
;
; If input is below table minimum: returns y[0], B=0
; If input is above table maximum: returns y[max], B=0
; If y values are decreasing (y1 < y0): result is correctly negated
; ---------------------------------------------------------------------------

table_ect_pair_interpolate:					; CODE XREF: injector_warmup+19p
								; async_throttle_inject+1Ep ...
; Wrapper: load ECT as input value then fall through to table_pair_interpolate
				ld	a, var_ect		; A = engine coolant temperature
; End of function table_ect_pair_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������


table_rA_pair_interpolate:					; CODE XREF: divide_d_by_x+937p
								; calc_iscv+11p ...
; Wrapper: load rA as input (B=0), skip the 'ld d, var_rpm_x_5p12' below
; Uses opcode 8Ch (.db 8Ch = 'cmp x, #xxxx') to consume the ld d instruction
; as an immediate operand, effectively skipping it
				clr	b			; B = 0, A already holds input value
; ���������������������������������������������������������������������������
				.db 8Ch				; Opcode trick: 8Ch = 'cmp x, #xxxx' (IMM)
								; consumes the next 2 bytes (ld d, var_rpm_x_5p12)
								; as its immediate operand, skipping that instruction
; ���������������������������������������������������������������������������

table_rpm_pair_interpolate:					; CODE XREF: divide_d_by_x+92Bp
								; calc_4ms_corrections+19p	...
; Wrapper: load RPM as input value then fall through to table_pair_interpolate
				ld	d, var_rpm_x_5p12	; D = RPM x 5.12 (engine speed)
; End of function table_rA_pair_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������


table_pair_interpolate:						; CODE XREF: divide_d_by_x+85Fp
								; sub_E865+186p ...
; 1D piecewise linear interpolation over a table of [x,y] byte pairs.
; On entry: Y = table pointer, D = input (A = x_in, B = 0)
				mov	d, x			; Preserve D (x_in) in X
				ld	a, [y]			; A = table count byte (N = num_pairs * 2); Y advances past it
				push	y			; Save pointer to first entry [x0,y0] on stack
				add	y, a			; Y now points to last entry [xN, yN] (one past end of data if 0-indexed)
				mov	x, d			; Restore D (x_in) into X (preserves it while Y is in use)
				cmp	a, y + 00h		; Compare x_in against last entry x value (xN)
				bcs	loc_C400		; If x_in < xN, input is within range - check lower bound

				pull	x			; x_in >= xN: input is above table max
				bra	loc_C405		; Return clamped value at table maximum

; ���������������������������������������������������������������������������

loc_C400:							; CODE XREF: table_pair_interpolate+7j
; x_in is below xN - check if also above x0 (lower bound)
				pull	y			; Restore Y to first entry pointer [x0,y0]
				cmp	a, y + 00h		; Compare x_in against first entry x value (x0)
				bcc	loc_C40B		; If x_in >= x0, input is within table range - find segment


loc_C405:							; CODE XREF: table_pair_interpolate+Aj
								; table_pair_interpolate+2Fj
; Clamp path: x_in is outside table range (below x0 or above xN)
; Y points to the appropriate boundary entry [x,y]
				ld	a, y + 01h		; A = y value at boundary (y0 or yN)
				clr	b			; B = 0 (no fractional component for clamped result)
				ret

; ���������������������������������������������������������������������������

loc_C409:							; CODE XREF: table_pair_interpolate+19j
; Advance to next table entry
				inc	y
				inc	y			; Y += 2: step forward one [x,y] pair

loc_C40B:							; CODE XREF: table_pair_interpolate+Fj
; Segment search: scan forward until x_in < table[Y+2].x
				cmp	a, y + 02h		; Compare x_in against next entry x (x1 = Y[2])
				bcc	loc_C409		; If x_in >= x1, advance to next segment
; Found segment: Y[0]=x0, Y[1]=y0, Y[2]=x1, Y[3]=y1
; x0 <= x_in < x1

; Calculate fractional position within segment: frac = (x_in - x0) * 256 / (x1 - x0)
				ld	a, y + 02h		; A = x1
				sub	a, y + 00h		; A = x1 - x0  (segment x width)
				push	a			; Push (x1 - x0) onto stack
				mov	x, d			; Restore D (x_in) from X
				sub	a, y + 00h		; A = x_in - x0  (offset within segment)
				mov	s, x			; SP = X: stack pointer now addresses (x1-x0) on stack
				div	d, x + 00h		; D=(x_in-x0)*256 / (x1-x0): B=frac [0..255], A=remainder
				inc	s			; Pop (x1-x0) from stack

; Calculate interpolated output: A_out = y0 + (y1-y0) * frac / 256
				ld	a, y + 03h		; A = y1
				sub	a, y + 01h		; A = y1 - y0  (segment y delta, signed)
				bcc	loc_C427		; If y1 >= y0 (delta positive), skip negation

; y delta is negative (y1 < y0): negate both delta and fraction
; This makes the multiply work correctly for falling segments
				neg	a			; A = y0 - y1  (positive delta magnitude)
				neg	b			; B = 256 - frac (invert fraction for falling direction)
				beq	loc_C405		; If frac was 0 (B wraps to 0), return y0 clamped

; Advance Y back by one entry to correct the y0 reference for falling segment
				inc	y
				inc	y			; Y now points to [x1,y1]: y0 for return is now Y[1] = y1

loc_C427:							; CODE XREF: table_pair_interpolate+2Bj
; Multiply y_delta by frac and add base y value
				push	b			; Push frac (B) onto stack
				mov	s, x			; SP = X: stack pointer now addresses frac on stack
				mul	a, x + 00h		; D = y_delta * frac: A = high byte (integer), B = low byte (fractional)
				add	a, y + 01h		; A = y0 + (y_delta * frac / 256)  [interpolated y]
				inc	s			; Pop frac from stack
				ret				; Return: A = result, B = fractional remainder

; End of function table_pair_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������

; Attributes: noreturn

; ---------------------------------------------------------------------------
; Fixed-step Table Lookup / Interpolation Family
;
; These functions look up a value from a table where the x-axis has a fixed
; (uniform) step size, so no x values need to be stored - only y values.
;
; Fixed table format in ROM:
;   Word 0 (2 bytes): [x_start (1 byte), x_step (1 byte)]
;                      x_start = x value of first table entry
;                      x_step  = spacing between x values (in D units)
;                                e.g. x_step=80h means each entry spans 128 units
;   Byte 2:            n_entries - 1 (max index, 0-based)
;   Bytes 3..N+2:      y values, one byte per entry, in x order
;
; The 'fixed' number in the function name (128, 64, 32 etc) is the x_step
; in D units after the D pre-scaling shift has been applied.
; The pre-scaling shifts adjust D so that an x_step of 256 fits one table slot.
;
; rD family: input is D (16-bit), scaled by shifting before lookup
;   table_rD_fixed128_interpolate: D >>= 1 (D/128 units per step)
;   table_rD_fixed64_interpolate:  D >>= 2 (D/64 units per step)
;   table_rD_fixed32_interpolate:  D >>= 3 (D/32 units per step)
;   table_rD_fixed16_interpolate:  D >>= 4 (D/16 units per step)
;   table_rD_fixed8_interpolate:   D >>= 5 (D/8 units per step) - falls through from fixed16
;   table_rD_fixed4_interpolate:   D <<= 1 (D*2 - upscales smaller values)
;   table_rD_fixed2_interpolate:   D <<= 2 (D*4 - upscales smaller values)
;   table_rD_fixed_interpolate:    D unmodified
;
; All rD fixed functions call table_rD_clamp then table_advance_y_to_entry then interp_y_pair:
;   table_rD_clamp: subtracts x_start from D, clamps to [0, max_offset]
;                   returns A = clamped offset (high byte of D-x_start), Y advanced past header
;   table_advance_y_to_entry:       advances Y by A+2 to point to the correct table entry pair [y0, y1]
;   interp_y_pair:       interpolates between Y[0] and Y[1] using B as the sub-step fraction
;
; rB family: input is B (8-bit), A = scale factor (max output)
;   table format: [x_start (1 byte), x_range (1 byte), y_max (1 byte)]
;   Scales B linearly: output = (B - x_start) * A / x_range, clamped to [0, y_max]
;   table_rB_fixed_16_interpolate: A = 16 (0x10)
;   table_rB_fixed_32_interpolate: A = 8  (0x08) [note: 8 = 256/32]
;   table_rB_fixed4_interpolate:   A = 4  (0x04)
; ---------------------------------------------------------------------------

table_rD_fixed128_interpolate:					; CODE XREF: check_boost_limit+5p
								; check_boost_limit+18p
; Pre-scale D: divide by 2 so x_step of 256 = 128 D-units per table slot
				shr	d			; D >>= 1 (fall through to fixed64)
; End of function table_rD_fixed128_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������

; Attributes: noreturn

table_rD_fixed64_interpolate:					; CODE XREF: divide_d_by_x+223Fp
								; sub_E865+Dp
; Pre-scale D: each shr halves the effective step size
				shr	d			; D >>= 1 (64 D-units per step after this)

table_rD_fixed32_interpolate:
				shr	d			; D >>= 1 (32 D-units per step after this)

table_rD_fixed16_interpolate:
				shr	d			; D >>= 1 (16 D-units per step after this)

table_rD_fixed8_interpolate:
				shr	d			; D >>= 1 (8 D-units per step); fall through to table_rD_fixed_interpolate
; End of function table_rD_fixed64_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������

; Attributes: noreturn thunk

j_table_rD_fixed_interpolate:					; CODE XREF: divide_d_by_x+1E24p
; Jump thunk - allows short-range bsr to reach table_rD_fixed_interpolate
				bra	table_rD_fixed_interpolate

; End of function j_table_rD_fixed_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������


table_rD_fixed4_interpolate:
; Pre-scale D upwards: multiply effective resolution by 2
				shl	d			; D <<= 1 (fall through to fixed2)
; End of function table_rD_fixed4_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������


table_rD_fixed2_interpolate:					; CODE XREF: sub_E865+CEp
				shl	d			; D <<= 1 (fall through to table_rD_fixed_interpolate)

table_rD_fixed_interpolate:					; CODE XREF: j_table_rD_fixed_interpolatej
; D is already in final scaled form.
; Call table_rD_clamp to subtract x_start, clamp to valid range, advance Y past header.
; Then jump to table_advance_y_to_entry to advance Y to the correct entry pair, then interpolate.
				bsr	table_rD_clamp		; A:B = clamped offset into table, Y advanced past header word
				bra	table_advance_y_to_entry		; Advance Y to entry pair [y0,y1], then interpolate (interp_y_pair)

; End of function table_rD_fixed2_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������


