; ��������������� S U B	R O U T	I N E ���������������������������������������


table_rB_fixed4_interpolate:					; CODE XREF: calc_ign_timing_min+71p
; Wrapper: set scale factor A=4, then jump to generic rB fixed interpolate
				ld	a, #04h			; A = 4 (output scale: result ranges 0..4)
