; End of function table_rB_fixed4_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������


table_ect_fixed_32_interpolate:					; CODE XREF: divide_d_by_x+1E2Bp
								; divide_d_by_x+224Bp ...
; Wrapper: load ECT into B, then fall through to table_rB_fixed_32_interpolate
				ld	b, var_ect		; B = engine coolant temperature
; End of function table_ect_fixed_32_interpolate


table_rB_fixed_32_interpolate:					; CODE XREF: divide_d_by_x+5D9p
								; divide_d_by_x+61Bp ...
; Wrapper: set scale factor A=8, skip the 'ld a, #10h' below via opcode trick
				ld	a, #08h			; A = 8 (output scale: result ranges 0..8)
; ���������������������������������������������������������������������������
				.db 8Ch				; Opcode trick: 8Ch = 'cmp x, #xxxx' (IMM)
								; consumes 'ld a, #10h' below as immediate operand, skipping it

; ��������������� S U B	R O U T	I N E ���������������������������������������


table_rB_fixed_16_interpolate:					; CODE XREF: divide_d_by_x+3E7p
								; divide_d_by_x+6DFp ...

; FUNCTION CHUNK AT C472 SIZE 00000004 BYTES

; Wrapper: set scale factor A=16, fall through to table_rB_fixed_rA_interpolate
				ld	a, #10h			; A = 16 (output scale: result ranges 0..16)
; On entry to table_rB_fixed_rA_interpolate:
;   Y  = pointer to fixed table: [x_start (1 byte), x_range (1 byte), y_max (1 byte)]
;   B  = input value
;   A  = output scale factor (max output value)
; Returns: A = (B - x_start) * A / x_range, clamped to [0, y_max]
;          B = fractional remainder of multiply

table_rB_fixed_rA_interpolate:					; CODE XREF: table_rB_fixed4_interpolate+2j
				sub	b, y + 00h		; B = B - x_start  (offset from table start)
				bcs	loc_C472		; If B < x_start (underflow), return y_max clamped

				push	a			; Save scale factor A on stack
				cmp	b, y + 01h		; Compare offset B against x_range
				ble	loc_C454		; If B <= x_range, input is within range

				ld	b, y + 01h		; B > x_range: clamp B to x_range (saturate at max)

loc_C454:							; CODE XREF: table_rB_fixed_16_interpolate+9j
; Compute: A = B * A / x_range  (scale B linearly across output range)
				mov	s, x			; SP = X: stack pointer now addresses saved A (scale factor)
				mov	b, a			; B = scale factor (A)
				mul	a, x + 00h		; D = B_offset * scale_factor: A = integer part, B = fractional
				inc	s			; Pop scale factor from stack
; Returns here: A = scaled result, B = fractional remainder
; End of function table_rB_fixed_16_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������


table_advance_y_to_entry:							; CODE XREF: table_rD_fixed2_interpolate+3j
								; map_rD_rX_interpolate+1Cp ...
; Advance Y to the correct [y0, y1] entry pair in the fixed table.
; On entry: A = index into the y[] array (0-based integer part of table offset / step)
;           Y = pointer to first y value (byte 3 of table, after the header word and count)
; After: Y points to y[index], ready for interp_y_pair to interpolate between Y[0] and Y[1]
				add	a, #02h			; A += 2: skip past the 2-byte header word in Y
				add	y, a			; Y += A: advance Y to entry pair [y[index], y[index+1]]
; End of function table_advance_y_to_entry


