interp_y_pair:							; CODE XREF: map_rD_rX_interpolate+2Dj
								; read_nv_afr_trim+36p	...
; Interpolate between Y[0] and Y[1] using B as the sub-step fraction [0..255].
; On entry: Y = pointer to [y0, y1] pair in table
;           B = fractional position within step (0=at y0, 255=just below y1)
;           A = B (fraction), passed in A (note: A is overwritten below)
; Returns:  A = interpolated result
				mov	b, a			; B = fractional offset (copy from A)
				beq	loc_C46F		; If fraction is 0, skip interpolation: return Y[0] directly

				push	b			; Save fraction on stack
				mov	s, x			; SP = X: stack now addresses fraction
				ld	a, y + 01h		; A = y1
				sub	a, y + 00h		; A = y1 - y0  (y delta, signed)
				bcc	loc_C46C		; If y1 >= y0 (positive delta), skip negation

; y delta is negative (y1 < y0): negate both delta and fraction
				neg	a			; A = y0 - y1  (positive magnitude)
				neg	b			; B = 256 - fraction (inverted for falling segment)
				xch	b, x + 00h		; Swap B with saved fraction on stack; B = saved fraction, stack = inverted
				inc	y			; Y++: shift base to y1 so add at end gives correct result

loc_C46C:							; CODE XREF: interp_y_pair+9j
				mul	a, x + 00h		; D = y_delta * fraction: A = integer part of (y_delta * frac / 256)
				inc	s			; Pop fraction from stack

loc_C46F:							; CODE XREF: interp_y_pair+1j
				add	a, y + 00h		; A = y0 + (y_delta * frac / 256)  [interpolated result]
				ret

; End of function interp_y_pair

