; ---------------------------------------------------------------------------
; 2D Map Lookup and Interpolation
;
; 2D map table format in ROM:
;   Word 0:   [x_step (1 byte), n_cols-1 (1 byte)]  - x-axis: step size and column count
;   Word 2:   [y_step (1 byte), n_rows-1 (1 byte)]  - y-axis: step size and row count
;   Bytes 4+: row-major z values, (n_cols) * (n_rows) bytes
;             z[row][col], row 0 first
;
; On entry to map_rD_rX_interpolate:
;   Y  = pointer to 2D map table
;   D  = x-axis input (scaled)
;   X  = y-axis input (scaled)
;
; Returns:
;   A  = bilinearly interpolated z value
;   B  = fractional remainder
;
; The pre-scaling wrappers adjust D or X before the lookup:
;   map_rD_32_rX_map_interpolate: D >>= 1  (x-axis step = 32 D-units after this)
;   map_rD_16_rX_map_interpolate: D >>= 4  (x-axis step = 16 D-units after this)
;
; Algorithm: bilinear interpolation
;   1. Clamp x (D) to column range, get col_index and col_frac
;   2. Clamp y (X) to row range, get row_index and row_frac
;   3. Compute row_offset = row_index * n_cols + col_fraction contribution
;   4. Look up z[row][col] and z[row+1][col] using table_advance_y_to_entry
;   5. Interpolate between the two z values using row_frac via interp_y_pair
; ---------------------------------------------------------------------------

map_rD_32_rX_map_interpolate:					; CODE XREF: sub_E76D+2Ap
; Pre-scale D: D >>= 1 so x_step of 256 = 32 D-units per column
				shr	d			; D >>= 1 (fall through to map_rD_16)
; End of function map_rD_32_rX_map_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������


map_rD_16_rX_map_interpolate:					; CODE XREF: divide_d_by_x+877p
; Pre-scale D: D >>= 4 so x_step of 256 = 16 D-units per column
				shr	d			; D >>= 1
				shr	d			; D >>= 1
				shr	d			; D >>= 1
				shr	d			; D >>= 1 (fall through to map_rD_rX_interpolate)
; End of function map_rD_16_rX_map_interpolate


; ��������������� S U B	R O U T	I N E ���������������������������������������


map_rD_rX_interpolate:						; CODE XREF: calc_iscv+3B9p
								; sub_E76D+1Dp
; Bilinear 2D map interpolation. D = x input, X = y input, Y = map pointer.

; Step 1: clamp x (D) to column range
				bsr	table_rD_clamp		; A = col_index, B = col_frac, Y advanced past x header

				push	x			; Save y input on stack
				st	d, var_temp_w		; Save col_index:col_frac for later
				mov	y, d			; Y = col_index:col_frac (re-use as temp)
				mov	d, x			; D = y input
				inc	y
				inc	y			; Y += 2: advance Y past x header to y header
				pull	d			; D = y input (restored)

; Step 2: clamp y (D) to row range
				bsr	table_rD_clamp		; A = row_index, B = row_frac, Y advanced past y header

; Step 3: compute row offset into data array
				push	b			; Save row_frac
				ld	b, x + 01h		; B = n_cols (from x header, still on stack)
				inc	b			; B = n_cols (convert from max_index to count)
				push	b			; Save n_cols
				mov	s, x			; SP = X: stack addresses n_cols
				mul	a, x + 00h		; D = row_index * n_cols (row base offset)
				st	y, var_temp_7A		; Save Y (data pointer)
				add	d, var_temp_7A		; D += data_ptr: absolute pointer to row start
				mov	d, y			; Y = row start pointer
				push	y			; Save row start pointer

; Step 4: look up z[row][col] - advance Y to correct column in this row
				ld	d, var_temp_w		; D = col_index:col_frac
				bsr	table_advance_y_to_entry	; Y -> z[row][col]

				st	a, var_temp_7A		; Save z[row][col]
				pull	y			; Restore row start pointer
				pull	b			; Restore n_cols
				add	y, b			; Y += n_cols: advance to next row start

; Step 4b: look up z[row+1][col] - same column in next row
				ld	d, var_temp_w		; D = col_index:col_frac (same column)
				bsr	table_advance_y_to_entry	; Y -> z[row+1][col]

				st	a, var_temp_7B		; Save z[row+1][col]

; Step 5: interpolate between z[row][col] and z[row+1][col] using row_frac
				ld	y, #var_temp_7A		; Y -> [z[row][col], z[row+1][col]]
				pull	b			; B = row_frac
				bra	interp_y_pair		; A = z[row][col] + (z[row+1][col] - z[row][col]) * row_frac / 256

; End of function map_rD_rX_interpolate


