; ---------------------------------------------------------------------------
; 16x16-bit multiply family
;
; mult_rDrX:  Full 16x16 -> 32-bit unsigned multiply.
;   On entry: D = multiplicand (A:B), X = multiplier (16-bit)
;   Returns:  D = D*X / 256  (middle 16 bits of 32-bit product, i.e. bits [23:8])
;             X = MSW of product (bits [31:16]) - non-zero means overflow
;             Y = LSW of product accumulator (internal intermediate)
;   Saturates: if MSW (X) is non-zero, D is clamped to 0FFFFh
;   Fraction:  0x80 in multiplier = 50%, 0x40 = 25%, etc.
;
; mult_rDrX_saturate: wrapper around mult_rDrX that additionally:
;   - Checks for overflow more explicitly
;   - Returns D = 0FFFFh with C set if product >= 0x10000
;   - Otherwise shifts result right 1 and returns via rorc
;
; mult_rBrX:  8x16 -> 16-bit multiply.
;   On entry: A = multiplier (8-bit), X = multiplicand (16-bit)
;   Falls through from mult_rBrX: moves A into B, then mul b,x performs A*X_low.
;   Returns: D = (A * X) / 256  (upper 16 bits of 24-bit product)
;
; mult_rBrX2: mult_rBrX then doubles result (rotates left 1 through carry).
;   Saturates to 0FFFFh on overflow.
;
; mult_rArX:  8x16 -> 16-bit multiply with carry propagation.
;   On entry: A = fraction (0x80=50%, 0x40=25%), X = value to scale
;   Returns: D = (A * X) / 256, X = same as D
;   Used to scale a variable by a fraction: 0x80 = 50%, 0x40 = 25%, etc.
; ---------------------------------------------------------------------------

mult_rDrX_saturate:							; CODE XREF: sub_E454+38p
								; sub_E454+5Ep
; Saturating 16x16 multiply. Calls mult_rDrX then checks for overflow.
				bsr	mult_rDrX		; D = D*X/256, X = MSW (non-zero = overflow)

				mov	y, d			; Y = result
				push	a			; Save A (high byte of result)
				mov	x, d			; X = result
				shr	d			; D >>= 1 (test if upper bits are set)
				and	a, #0FFh		; Isolate high byte
				pull	a			; Restore A
				beq	loc_C504		; If high byte was zero, no overflow

				ld	d, #0FFFFh		; Saturate D to maximum
				setc				; C = 1: overflow occurred

loc_C504:							; CODE XREF: mult_rDrX_saturate+9j
				xch	a, b			; Swap A and B
				rorc	b			; Rotate B right through carry
				ret

; End of function mult_rDrX_saturate


; ��������������� S U B	R O U T	I N E ���������������������������������������

; 16x16 -> 32-bit unsigned multiply.
; D = D * X / 256  (middle 16 bits of 32-bit product).
; X = MSW of product (bits [31:16]). If X != 0, product overflowed 16 bits.
; D is saturated to 0FFFFh if MSW is non-zero.
; Computes the full 32-bit product of D (16-bit) x X (16-bit) using
; four 8x8 partial products, then assembles and saturates.

mult_rDrX:							; CODE XREF: mult_rDrX_saturatep
								; divide_d_by_x+1418p ...
