				push	x			; Save X on stack
				mov	s, x			; SP = X: stack addresses [D_hi, D_lo, X_hi, X_lo]
				mul	a, x + 00h		; partial: A_hi * X_lo -> D
				mov	d, y			; Y = partial product low word
				ld	a, x + 00h		; A = X_lo
				mul	a, x + 03h		; partial: X_lo * D_lo -> D
