; ---------------------------------------------------------------------------
; calc_rpm: compute var_rpm_x_5p12 from var_ne_sum3
;
; Input:  var_ne_sum3 = sum of 3 consecutive NE periods (4 us units)
;         A = caller-supplied count (normally 0; used to pass ne_sum3 scaling)
;
; Output: D = var_rpm_x_5p12 = RPM * 5.12 (16-bit)
;
; Formula:
;   24 NE pulses per revolution (4 cylinders x 6 pulses each)
;   var_ne_sum3 covers 3 pulses = 3/24 = 1/8 revolution
;   Period for 1 rev (us) = var_ne_sum3 * 4 * 8 = var_ne_sum3 * 32
;   RPM = 60,000,000 / (var_ne_sum3 * 32) = 1,875,000 / var_ne_sum3
;   RPM * 5.12 = 9,600,000 / var_ne_sum3
;
; Example values:
;    750 RPM: var_ne_sum3 = 2500,  var_rpm_x_5p12 = 3840
;   1000 RPM: var_ne_sum3 = 1875,  var_rpm_x_5p12 = 5120
;   2000 RPM: var_ne_sum3 =  938,  var_rpm_x_5p12 = 10240
;   4000 RPM: var_ne_sum3 =  469,  var_rpm_x_5p12 = 20480
;   6000 RPM: var_ne_sum3 =  313,  var_rpm_x_5p12 = 30720
;
; Algorithm: reciprocal approximation via normalise-then-divide
;   1. Clamp ne_sum3 to minimum 0x0300 (prevents divide overflow at low RPM)
;   2. Normalise D left until MSB of A (high byte) is set, counting shifts
;      Each shift also advances X one step deeper into the divide_rD cascade
;   3. Divide normalised D by 16 (divide_rD_16)
;   4. Use A (normalised high byte) as index into RPM scale constant table
;      via table_advance_y_to_entry, positioning Y at the correct constant pair
;   5. Shift D right 1, add 0x40 to A (interpolation fraction)
;   6. Call divide function via X (selected during normalise loop) to scale down
;   7. Shift D left 1 to restore final scale
;   Result D approximates 9,600,000 / var_ne_sum3 = RPM * 5.12
; ---------------------------------------------------------------------------

calc_rpm:							; CODE XREF: divide_d_by_x+31Ap
								; calc_ign_timing_min+16p
				ld	d, var_ne_sum3		; D = sum of 3 NE periods (4 us units)
				cmp	a, #03h			; Is high byte >= 3 (ne_sum3 >= 0x0300 = 768)?
				bcc	loc_C8C9			; Yes: ne_sum3 is large enough, proceed

				ld	d, #0300h			; Clamp to minimum 0x0300 (limits max RPM output)

loc_C8C9:							; CODE XREF: calc_rpm+4j
								; DATA XREF: calc_rpm+1Fo
				ld	x, #divide_rD_64		; X = base divide function pointer

; Normalisation loop: shift D left until MSB of A (high byte) is set
; Each iteration: advance X one step into divide cascade, shift D left 1
; After N iterations: D = ne_sum3 << N, X points N steps past divide_rD_64
; Loop exits when A is negative (MSB of high byte set = D normalised to 0x8xxx)
loc_C8CC:							; CODE XREF: calc_rpm+11j
				cmpz	a				; Test if high byte A is negative (MSB set)
				bmi	loc_C8DC			; Yes: D is normalised, exit loop

				inc	x				; Advance divide function pointer one step
				shl	d				; D <<= 1 (normalise left)
				bra	loc_C8CC

; RPM scale constant table - indexed by normalised D high byte after divide_rD_16
; Each pair [y0, y1] provides the interpolation endpoints for that RPM range
; Values: 0xA4(164), 0x84(132), 0x6A(106), 0x55(85), 0x43(67),
;         0x34(52),  0x27(39),  0x1C(28),  0x12(18)
				.db 0A4h, 84h, 6Ah, 55h, 43h, 34h, 27h,	1Ch, 12h

loc_C8DC:							; CODE XREF: calc_rpm+Dj
				jsr	divide_rD_16			; D >>= 4: A = normalised high byte, used as table index

				ld	y, #loc_C8C9			; Y = base of RPM scale constant table
				push	x				; Save divide function pointer
				jsr	table_advance_y_to_entry	; Y -> constant pair [y0, y1] for this RPM range

				shr	d				; D >>= 1: B = sub-range fraction for interpolation
				add	a, #40h			; A += 0x40: add base fraction offset
				pull	x				; Restore divide function pointer
				jsr	x + 00h				; Call selected divide function to scale D to RPM*5.12 range

				shl	d				; D <<= 1: restore final scale
				ret					; Return D = RPM * 5.12

; End of function calc_rpm

