; ---------------------------------------------------------------------------
; injector_warmup: fire one batch injection pulse, ECT- or RPM-scaled
;
; Called from the main 4ms loop (divide_d_by_x:loc_CAD4) right after the
; overrun/deceleration fuel-cut decision has been made for this cycle, while
; var_limiter_flags.0 still holds *last* cycle's fuel-cut state (it is cleared
; immediately after this call, at loc_CAD4+3).
;
; Gates (all must pass, else return doing nothing):
;   var_flags_46.0 = 0 (RPM has risen past the ~200-400rpm cranking/stall
;     hysteresis band - not still cranking)
;   unk_44.0 = 1 (idle-debounce latch: mirrors var_flags_46.2 from one
;     hysteresis stage back, i.e. throttle was confirmed closed)
;   var_flags_46.2 = 0 (the throttle-closed debounce timer is not currently
;     mid-countdown - the idle state has settled)
;
; Path selection (var_limiter_flags.0, still last cycle's value here):
;   Clear (not coming out of an overrun fuel cut): ECT-indexed path -
;     table_ect_unk_C1D8 via table_ect_pair_interpolate
;   Set (resuming from an overrun fuel cut this cycle): RPM-indexed path -
;     table_rpm_unk_C1D2 via table_rB_fixed_32_interpolate
;   NOTE: table_ect_unk_C1D8's declared byte count (06h) does not match the
;   4 (x,y) pairs laid out after it in ROM - table layout not fully verified.
;
; Either path leaves a raw pulse-width value in D; divide_rD_64 scales it
; down and injectors_batch_update fires all 4 injectors simultaneously with it.
; ---------------------------------------------------------------------------

injector_warmup:							; CODE XREF: divide_d_by_x:loc_CAD4p
				tbbs	bit0, var_flags_46, locret_CD8A ; Still in cranking/stall RPM band: skip

				tbbc	bit0, unk_44, locret_CD8A	; Idle-debounce latch not set: skip

				tbbs	bit2, var_flags_46, locret_CD8A ; Throttle-closed debounce still counting: skip

				tbbc	bit0, var_limiter_flags, loc_CD7E ; No pending overrun-cut recovery: use ECT path

				ld	y, #table_rpm_unk_C1D2		; Recovering from overrun cut: RPM-indexed table
				ld	b, var_rpm_div_25
				jsr	table_rB_fixed_32_interpolate

				bra	loc_CD84

; ���������������������������������������������������������������������������

loc_CD7E:							; CODE XREF: injector_warmup+9j
				ld	y, #table_ect_unk_C1D8		; Normal case: ECT-indexed table
				jsr	table_ect_pair_interpolate


loc_CD84:							; CODE XREF: injector_warmup+14j
				jsr	divide_rD_64			; Scale raw table result down to a pulse width

				jsr	injectors_batch_update		; Fire all 4 injectors simultaneously


locret_CD8A:							; CODE XREF: injector_warmupj
								; injector_warmup+3j ...
				ret

; End of function injector_warmup

