; ---------------------------------------------------------------------------
; update_idle_timing_ramp: ramp up idle ignition timing minimum
;
; Called from iv6_4ms_process every 4ms.
;
; Condition: var_flags_4E_copy_1D3 == 0x08 (only bit3 set)
;   bit3 of var_flags_4E is set when engine is in idle/low-load condition
;   (low RPM, low speed, no overrun, no enrichment flags active).
;   The == 0x08 check requires ALL other flags to be clear, meaning this
;   only activates in a clean idle state with no competing corrections.
;
; When active: var_idle_timing_ramp += 4 per 4ms, saturated at 0xFF.
; This ramp is used by calc_ign_timing_min to compute var_ign_timing_min:
;   var_ign_timing_min = min(var_idle_timing_ramp, unk_15F) + var_ect_unk_160
;   Higher ramp = higher minimum timing = more advance enforced at idle.
; The effect is that ignition advance is progressively raised during stable
; idle until the idle speed stabilises (ISCV closes, ramp stops or decays).
; ---------------------------------------------------------------------------

update_idle_timing_ramp:							; CODE XREF: iv6_4ms_process+5Cp
				ld	b, var_flags_4E_copy_1D3	; B = copy of fuel/mode flags
				cmpb	b, #08h				; Flags == 0x08 (only idle bit set)?
				bne	locret_EC06			; No: not in clean idle state, skip

				ld	b, #04h				; Step = 4 counts per 4ms
				add	b, var_idle_timing_ramp	; B = ramp + step
				bcc	loc_EC03			; No overflow: store result
				ld	b, #0FFh			; Overflow: saturate at 0xFF

loc_EC03:							; CODE XREF: update_idle_timing_ramp+Cj
				st	b, var_idle_timing_ramp	; Update ramp value

locret_EC06:							; CODE XREF: update_idle_timing_ramp+5j
				ret

; End of function update_idle_timing_ramp


; ��������������� S U B	R O U T	I N E ���������������������������������������


; Ramp var_cyl_rpm_filtered by +4 when misfire condition active (var_cnt_DA > 0x14)
; A = 0 when no misfire; grows toward 0xFF under sustained misfire.
ramp_misfire_correction:							; CODE XREF: divide_d_by_x+C5Cp
				clr	a				; Default: A = 0
				cmp	#14h, var_cnt_DA		; var_cnt_DA > 0x14 (misfire active)?
				bcs	loc_EC16			; No: store 0
				ld	a, var_cyl_rpm_filtered
				add	a, #04h				; Ramp up +4
				bcc	loc_EC16			; No overflow: store
				ld	a, #0FFh			; Saturate at 0xFF

loc_EC16:							; CODE XREF: ramp_misfire_correction+4j
								; ramp_misfire_correction+Bj
				st	a, var_cyl_rpm_filtered
				ret

; End of function ramp_misfire_correction


