				; public int_vector_e_ne
; ---------------------------------------------------------------------------
; NE (engine speed) pulse interrupt handler
;
; Triggered on each NE pulse from the distributor (24 pulses per revolution:
; 6 pulses per cylinder x 4 cylinders).
;
; var_ne_count encoding:
;   bits 3..0 = position counter within cylinder (0..5, 6 positions)
;   bits 7..4 = cylinder counter (0x00, 0x10, 0x20, 0x30 = cylinders 1..4)
;   0xFF      = uninitialised / invalid (starter cranking init state)
;
; G1 and G2 signals (PORTA.6 and PORTA.7) are used to synchronise the
; position counter to a known crank position:
;   G2 low:  expected when ne_count = 0x35 (cylinder 3, position 5)
;   G1 low:  expected when ne_count = 0x15 (cylinder 1, position 5)
;
; After updating var_ne_count, triggers iv6_ne_process via IV6 software
; interrupt to handle ignition and injection scheduling.
; ---------------------------------------------------------------------------

int_vector_e_ne:						; DATA XREF: ROM:FFFAo
				clrb	bit6, IRQLL		; Clear NE interrupt latch (ASR2 edge)
				push	x
				push	y
				ld	b, var_ne_count		; B = current NE counter
								; bits 3..0: position within cylinder (0..5)
								; bits 7..4: cylinder index (0x00/10/20/30)
								; 0xFF = uninitialised
				bmi	int_vector_e_ne_EFD8	; If ne_count = 0xFF (uninitialised), skip error detection

; Sanity check: ignore NE pulses if 4ms counter too low (engine just started)
				cmp	#3Fh, var_4ms_cnt_ne_C2
				bcs	int_vector_e_ne_EFD8	; Skip if 4ms count < 0x3F

; G1/G2 sync error detection
				ld	a, unk_189			; A = G1/G2 error accumulator
				tbbc	bit6, IRQL, int_vector_e_ne_EFC8 ; If ASR2 edge not set in IRQL, skip increment

				inc	a				; Increment error accumulator
				bne	int_vector_e_ne_EFC8	; If not wrapped to zero, continue

				dec	a				; Clamp at 0xFF (prevent wrap-around to 0)

int_vector_e_ne_EFC8:						; CODE XREF: ROM:EFC1j
								; ROM:EFC5j
				tbbs	bit6, PORTA, int_vector_e_ne_EFD9 ; If G1 (PORTA.6) is high, skip error check

; G1 is low - check error accumulator value
				cmp	a, #02h
				beq	int_vector_e_ne_EFD6	; A=2: clear error flag (G1/G2 recovered)

				cmp	a, #06h
				bcs	int_vector_e_ne_EFD8	; A < 6: not yet at error threshold

				setb	bit7, var_error_flags1	; A >= 6: set G1/G2 signal error flag
; ���������������������������������������������������������������������������
				.db  8Ch ; �
; ���������������������������������������������������������������������������

int_vector_e_ne_EFD6:						; CODE XREF: ROM:EFCDj
				clrb	bit7, var_error_flags1

int_vector_e_ne_EFD8:						; CODE XREF: ROM:EFB7j
								; ROM:EFBCj ...
				clr	a

int_vector_e_ne_EFD9:						; CODE XREF: ROM:int_vector_e_ne_EFC8j
; G1 high path: update error accumulator and proceed to counter update
				st	a, unk_189			; Save updated error accumulator
				clrb	bit6, IRQL			; Clear ASR2 interrupt latch

; Read ne_count and check G1/G2 sync signals
				ld	b, var_ne_count		; B = current NE counter
								; bits 3..0: position within cylinder (0..5)
								; bits 7..4: cylinder index (0x00/10/20/30)
				tbbc	bit7, PORTA, int_vector_e_ne_F001 ; G2 low -> sync check path
				tbbc	bit6, PORTA, int_vector_e_ne_F008 ; G1 low -> sync check path

; Both G1 and G2 are high: normal NE pulse, advance the counter
				cmpz	b				; Check if ne_count is uninitialised (0xFF = negative)
				bmi	int_vector_e_ne_F01C	; If uninitialised, store without incrementing

; Increment position counter (bits 3..0)
				mov	b, a				; B = ne_count (A was loaded from var_ne_count earlier)
				inc	b				; B = ne_count + 1 (tentative next value)
				and	a, #0Fh			; A = position nibble only (bits 3..0)
				cmp	a, #05h			; Has position reached 5 (last of 0..5)?
				bcs	int_vector_e_ne_F01C	; Position < 5: simple increment, store B

; Position has reached 5: wrap position to 0 and advance cylinder counter
