				cmp	b, #15h			; Is ne_count = 0x15 (expected at G1 low)?
				beq	int_vector_e_ne_F01B	; Yes: counter in sync, store A=0x20


int_vector_e_ne_F00E:						; CODE XREF: ROM:F006j
; Counter not at expected sync point: check if uninitialised
