; ---------------------------------------------------------------------------
; Injector control table: one entry per injector (4 injectors)
; Each entry spans 3 bytes across 3 rows of the table:
;   [+0]: LDOUT bit mask  - bit to check/set when injector is ON
;   [+4]: LDOUT AND mask  - complement, used to clear the bit (turn OFF)
;   [+8]: CPRn address    - compare register that fires when pulse width expires
;
; Entry | DOUT bit | LDOUT bit | LDOUT mask | CPRn | Injector
;   [0] | DOUT.4   | 0x10      | 0xEF       | CPR4 | Injector 1
;   [1] | DOUT.6   | 0x40      | 0xBF       | CPR6 | Injector 2
;   [2] | DOUT.7   | 0x80      | 0x7F       | CPR7 | Injector 3
;   [3] | DOUT.5   | 0x20      | 0xDF       | CPR5 | Injector 4
; ---------------------------------------------------------------------------
table_injector_control:		.db 10h, 40h, 80h, 20h		; DATA XREF: iv6_ne_process+238o
								; iv6_ne_process+246o ...
								; Row 0: LDOUT bit mask (injector ON state)
				.db 0EFh, 0BFh,	7Fh, 0DFh	; Row 1: LDOUT AND mask (injector OFF clear)
				.db CPR4, CPR6,	CPR7, CPR5	; Row 2: CPRn register addresses

