				mov	x, d			; rD = rX
				add	d, word_125		; rD = rX + ((mPIM / 256 * 73))	+
								;	    ((mPIM % 256) * 73)	/ 256);
								; rD = mPim + (mPim * 73 / 256);
								; rD = mPim * 1.285156
				bcc	loc_FBE0		; Jump if no overflow

