; ---------------------------------------------------------------------------
; adc_handler_o2_heater: O2 sensor heater current measurement
;
; Input: X = raw 16-bit ADC result. Only high byte (A) used.
;
; Scaling: var_adc_o2_heater = A * 4, saturated to 0xFF
;   A = 0..63  -> result = 0..252
;   A > 63     -> result = 0xFF (saturated)
;
; Also reads O2 sensor voltage (var_adc_o2_sensor) to select from
; table_adc_lambda_C249 for lambda integrator update.
; var_adc_lambda is a signed integrator: increments when O2 is lean,
; decrements when rich, used for closed-loop fuel trim.
; Lambda direction depends on throttle state (var_flags_46.2):
;   Throttle closed: use rich-direction table entries
;   Throttle open: use lean-direction table entries, offset by O2 sensor bits
;
; Outputs: var_adc_o2_heater, var_adc_lambda (local + dmatx_adc_lambda to CPU2)
; ---------------------------------------------------------------------------

adc_handler_o2_heater:						; DATA XREF: ROM:table_adc_handlero
				mov	x, d			; X = raw ADC result (preserve for O2 lambda path)
				shl	d			; D <<= 1 (A * 2)
				bcs	loc_FC64		; Overflow: saturate to 0xFF

