				ld	y, #tha_adc_limits	; Check and clamp raw ADC within THA sensor range
				jsr	y + (clamp_rB -	tha_adc_limits)

				ld	a, var_flags_18C	; A = current sensor status flags
				bcc	loc_FF0D		; C clear: value in range

				cmpb	a, #04h			; Already flagged as out-of-range (bit2 set)?
				bne	loc_FEFC		; Yes: skip first-error setup

				or	a, #04h			; Set THA out-of-range flag (var_flags_18C.2)
				clr	var_cnt_sensor_error	; Reset error counter on first detection

loc_FEFC:							; CODE XREF: ROM:FEF6j
				tbbs	bit2, unk_40, loc_FF05

				cmp	#0Fh, var_cnt_sensor_error ; Check if less than	15 reads out of	range
				bcs	loc_FF09		; Jump if so

; ���������������������������������������������������������������������������
