				setb	bit4, var_error_flags2	; Set THAM sensor error	flag

loc_FF40:							; CODE XREF: ROM:FF39j
				ld	b, #79h			; 79h ^	0FFh = 86h - Default to	20 deg
				bra	loc_FF4B

; ���������������������������������������������������������������������������

loc_FF44:							; CODE XREF: ROM:FF29j
