; ---------------------------------------------------------------------------
; adc_handler_battery: battery voltage measurement
;
; Input: B = raw 8-bit ADC value (voltage divider ~3:1, measuring 0-15V)
;
; Threshold 0x53 = approximately 6.5V:
;   If voltage >= 6.5V AND PRAM valid AND init flag set:
;     Release knock MCU reset (DOUT.2 high)
;   This ensures knock MCU only starts after battery is stable
;
; Battery compensation:
;   table_rB_fixed_32_interpolate on table_inj_battery_adjust:
;   Produces an injector open-time adjustment to compensate for battery
;   voltage variation (injectors open slower at low voltage)
;   var_inj_battery_adjust = table_rB_fixed_32_interpolate(B) / 64
;
; Outputs: var_adc_battery, dmatx_battery to CPU2, var_inj_battery_adjust
; ---------------------------------------------------------------------------

adc_handler_battery:						; DATA XREF: ROM:table_adc_handlero
				st	b, var_adc_battery		; Store raw battery ADC
				st	b, dmatx_battery		; Send to CPU2 via DMA
				tbbc	bit5, RAMST, loc_FF6A		; PRAM not valid: skip knock MCU release

				cmp	b, #53h				; Battery voltage >= 6.5V?
				bcs	loc_FF6A			; No: skip knock MCU release

				tbs	bit6, unk_44			; Init flag set?
				beq	loc_FF6A			; No: skip

				setb	bit2, DOUT			; Release knock MCU reset (DOUT.2 high)

loc_FF6A:							; CODE XREF: adc_handler_battery+5j
								; adc_handler_battery+Aj ...
; Compute injector battery compensation
				ld	b, var_adc_battery		; Reload battery ADC (table lookup needs B)
				ld	y, #table_inj_battery_adjust
				jsr	table_rB_fixed_32_interpolate	; Look up compensation factor
				jsr	divide_rD_64			; Scale down
				st	d, var_inj_battery_adjust	; Store injector open-time compensation
				jmp	adc_complete

; End of function adc_handler_battery

; ���������������������������������������������������������������������������

; ---------------------------------------------------------------------------
; adc_handler_ect: engine coolant temperature sensor (ECT)
;
; Input: B = raw 8-bit ADC value from ECT NTC thermistor
;
; NTC thermistor: XOR 0xFF on both bytes so high var_ect = hot, low = cold.
; Lower byte also masked to 0xC0 (top 2 bits only = 10-bit effective resolution).
;
; On out-of-range:
;   Default: X = 0x1B00, then XOR: A=0xE4, B=0x00 AND 0xC0=0x00
;   var_ect = 0xE400 (approximately 82 degC default)
;   After 15 consecutive errors: set var_error_flags1.3, var_diag_errors_5.3
;   First error: set var_flags_18C.1, reset error counter
;
; Outputs: var_ect (16-bit, XOR-inverted + masked), dmatx_ect to CPU2
; ---------------------------------------------------------------------------

adc_handler_ect:						; DATA XREF: ROM:table_adc_handlero
				ld	y, #ect_adc_limits	; Check and clamp raw ADC within ECT sensor range
				jsr	y + (clamp_rB -	ect_adc_limits)

				ld	a, var_flags_18C	; A = current sensor status flags
				bcc	loc_FF9F		; C clear: value in range

				cmpb	a, #02h			; Already flagged as out-of-range (bit1 set)?
				bne	loc_FF8D		; Yes: skip first-error setup

				or	a, #02h			; Set ECT out-of-range flag (var_flags_18C.1)
				clr	var_cnt_sensor_error	; Reset error counter on first detection

loc_FF8D:							; CODE XREF: ROM:FF87j
				tbbs	bit2, unk_40, loc_FF96

				cmp	#0Fh, var_cnt_sensor_error
				bcs	loc_FF9A

; ���������������������������������������������������������������������������
				.db  8Ch ; �
; ���������������������������������������������������������������������������

loc_FF96:							; CODE XREF: ROM:loc_FF8Dj
				setb	bit3, var_diag_errors_5
				setb	bit3, var_error_flags1

loc_FF9A:							; CODE XREF: ROM:FF93j
				ld	x, #1B00h		; Default to 82	deg
				bra	loc_FFA6

; ���������������������������������������������������������������������������

loc_FF9F:							; CODE XREF: ROM:FF83j
				tbbs	bit2, unk_40, loc_FFA4

				clrb	bit3, var_error_flags1

loc_FFA4:							; CODE XREF: ROM:loc_FF9Fj
				and	a, #0FDh

loc_FFA6:							; CODE XREF: ROM:FF9Dj
				st	a, var_flags_18C
				mov	x, d
				xor	a, #0FFh
				xor	b, #0FFh
				and	b, #0C0h
				st	d, var_ect
				st	d, dmatx_ect
				jmp	adc_complete


